import{STOP}from"./constants.js";import{getAliasReExportMap,getPassThroughReExportSources,getStarReExportSources}from"./visitors.js";export const walkDown=(o,r,t,s,f,e=new Set)=>{const i=`${r}:${t}`;if(e.has(i))return!1;e.add(i);const n=o.get(r);if(!n?.importedBy)return!1;const a=t.split("."),c=a.shift();if(!c)return!1;const p=n.importedBy,S=p.import.get(c);if(S)for(const o of S){if(s(r,c,o,c,f.has(o),"import")===STOP)return!0}const k=p.importAs.get(c);if(k)for(const[o,t]of k)for(const e of t){if(s(r,c,e,o,f.has(e),"importAs")===STOP)return!0}for(const[o,e]of p.importNs)for(const i of e){if(s(r,t,i,`${o}.${t}`,f.has(i),"importNS")===STOP)return!0}let h=!1;if(!h){const i=getPassThroughReExportSources(p,c);if(i)for(const n of i){if(s(r,c,n,c,f.has(n),"reExport")===STOP){h=!0;break}if(walkDown(o,n,t,s,f,e)){h=!0;break}}}if(!h){const t=getAliasReExportMap(p,c);if(t)for(const[i,n]of t){for(const t of n){if(s(r,c,t,i,f.has(t),"reExportAs")===STOP){h=!0;break}if(walkDown(o,t,[i,...a].join("."),s,f,e)){h=!0;break}}if(h)break}}if(!h)for(const[i,n]of p.reExportNs){for(const a of n){if(s(r,t,a,`${i}.${t}`,f.has(a),"reExportNS")===STOP){h=!0;break}if(walkDown(o,a,`${i}.${t}`,s,f,e)){h=!0;break}}if(h)break}if(!h){const i=getStarReExportSources(p);if(i)for(const n of i){if(s(r,c,n,c,f.has(n),"reExportStar")===STOP){h=!0;break}if(walkDown(o,n,t,s,f,e)){h=!0;break}}}return h};